import React, { useState } from 'react';

// --- 1. Data Interfaces ---
interface Patient {
  id: number;
  first_name: string;
  last_name: string;
  date_of_birth: string;
  gender: string;
  contact_number: string;
  email: string;
}

interface Doctor {
  id: number;
  first_name: string;
  last_name: string;
  specialization: string;
  email: string;
}

interface Appointment {
  id: number;
  patientId: number;
  doctorId: number;
  appointment_date: string;
  status: string;
}

interface CardProps {
  title: string;
  sub: string;
  onEdit: () => void;
  onDelete: () => void;
  color?: string;
  tag?: string;
}

// --- MAIN APP ---
function App() {
  const [activeTab, setActiveTab] = useState<'patients' | 'doctors' | 'appointments'>('patients');
  const [showModal, setShowModal] = useState(false);

  const [patients, setPatients] = useState<Patient[]>([
    { id: 1, first_name: "Alice", last_name: "Smith", date_of_birth: "1990-05-15", gender: "Female", contact_number: "555-0199", email: "alice@email.com" }
  ]);
  const [doctors, setDoctors] = useState<Doctor[]>([
    { id: 1, first_name: "Gregory", last_name: "House", specialization: "Diagnostic Medicine", email: "house@princeton.edu" }
  ]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);

  const [editId, setEditId] = useState<number | null>(null);
  const [formData, setFormData] = useState<any>({});

  const openModal = (item?: any) => {
    if (item) {
      setEditId(item.id);
      setFormData(item);
    } else {
      setEditId(null);
      setFormData({});
    }
    setShowModal(true);
  };

  const handleSave = () => {
    const id = editId || Date.now();
    const dataWithId = { ...formData, id };

    if (activeTab === 'patients') {
      setPatients(editId ? patients.map(p => p.id === editId ? dataWithId : p) : [dataWithId, ...patients]);
    } else if (activeTab === 'doctors') {
      setDoctors(editId ? doctors.map(d => d.id === editId ? dataWithId : d) : [dataWithId, ...doctors]);
    } else if (activeTab === 'appointments') {
      setAppointments(editId ? appointments.map(a => a.id === editId ? dataWithId : a) : [dataWithId, ...appointments]);
    }
    closeModal();
  };

  const deleteItem = (id: number) => {
    if (activeTab === 'patients') setPatients(patients.filter(p => p.id !== id));
    if (activeTab === 'doctors') setDoctors(doctors.filter(d => d.id !== id));
    if (activeTab === 'appointments') setAppointments(appointments.filter(a => a.id !== id));
  };

  const closeModal = () => {
    setShowModal(false);
    setEditId(null);
    setFormData({});
  };

  return (
    <div className="flex min-h-screen bg-[#00152b] text-white font-sans italic">
      <aside className="w-80 bg-[#000d1a] border-r-4 border-yellow-400 p-10 flex flex-col shadow-2xl">
        <h1 className="text-4xl font-black text-yellow-400 italic mb-12 tracking-tighter">MED-TRAIL</h1>
        <nav className="flex flex-col gap-4">
          {(['patients', 'doctors', 'appointments'] as const).map((tab) => (
            <button
              key={tab}
              onClick={() => { setActiveTab(tab); closeModal(); }}
              className={`text-left px-8 py-5 rounded-2xl font-black uppercase tracking-widest transition-all ${
                activeTab === tab ? 'bg-yellow-400 text-black translate-x-3 shadow-[-10px_0_0_0_#fff]' : 'text-blue-300 hover:bg-blue-900/40'
              }`}
            >
              {tab}
            </button>
          ))}
        </nav>
      </aside>

      <main className="flex-1 p-16 overflow-y-auto">
        <header className="flex justify-between items-center mb-12">
          <h2 className="text-6xl font-black uppercase tracking-tighter italic">
            {activeTab} <span className="text-yellow-400">Hub</span>
          </h2>
          <button onClick={() => openModal()} className="bg-yellow-400 text-black px-10 py-5 font-black uppercase shadow-[8px_8px_0_0_#fff] hover:bg-white transition-all">
            + Create Record
          </button>
        </header>

        <div className="space-y-6">
          {activeTab === 'patients' && patients.map(p => (
            <Card key={p.id} title={`${p.first_name} ${p.last_name}`} sub={`${p.email} | ${p.contact_number}`} tag={p.gender} onEdit={() => openModal(p)} onDelete={() => deleteItem(p.id)} />
          ))}
          {activeTab === 'doctors' && doctors.map(d => (
            <Card key={d.id} title={`Dr. ${d.last_name}`} sub={d.specialization} color="border-blue-500" onEdit={() => openModal(d)} onDelete={() => deleteItem(d.id)} />
          ))}
          {activeTab === 'appointments' && appointments.map(a => {
            const patient = patients.find(p => p.id === Number(a.patientId));
            const doctor = doctors.find(d => d.id === Number(a.doctorId));
            return (
              <Card key={a.id} title={`${patient?.last_name || 'Patient'} ➔ Dr. ${doctor?.last_name || 'Doctor'}`} sub={`Date: ${a.appointment_date}`} tag={a.status} color="border-green-500" onEdit={() => openModal(a)} onDelete={() => deleteItem(a.id)} />
            );
          })}
        </div>

        {showModal && (
          <div className="fixed inset-0 bg-black/95 flex items-center justify-center z-50 backdrop-blur-md">
            <div className="bg-white text-black w-full max-w-2xl p-12 rounded-[50px] border-[12px] border-yellow-400 shadow-2xl">
              <h3 className="text-4xl font-black uppercase italic mb-8 border-b-8 border-blue-600 inline-block">
                {editId ? 'Edit' : 'Register'} {activeTab.slice(0, -1)}
              </h3>

              <div className="grid grid-cols-2 gap-6 mb-10">
                {activeTab === 'patients' && (
                  <>
                    <Input label="First Name" value={formData.first_name} onChange={(v: string) => setFormData({...formData, first_name: v})} />
                    <Input label="Last Name" value={formData.last_name} onChange={(v: string) => setFormData({...formData, last_name: v})} />
                    <Input label="DOB" type="date" value={formData.date_of_birth} onChange={(v: string) => setFormData({...formData, date_of_birth: v})} />
                    <Input label="Gender" value={formData.gender} onChange={(v: string) => setFormData({...formData, gender: v})} />
                    <Input label="Contact" value={formData.contact_number} onChange={(v: string) => setFormData({...formData, contact_number: v})} />
                    <Input label="Email" value={formData.email} onChange={(v: string) => setFormData({...formData, email: v})} />
                  </>
                )}
                {activeTab === 'doctors' && (
                  <>
                    <Input label="First Name" value={formData.first_name} onChange={(v: string) => setFormData({...formData, first_name: v})} />
                    <Input label="Last Name" value={formData.last_name} onChange={(v: string) => setFormData({...formData, last_name: v})} />
                    <Input label="Specialization" value={formData.specialization} onChange={(v: string) => setFormData({...formData, specialization: v})} />
                    <Input label="Email" value={formData.email} onChange={(v: string) => setFormData({...formData, email: v})} />
                  </>
                )}
                {activeTab === 'appointments' && (
                  <div className="col-span-2 space-y-4">
                    <Select label="Patient" value={formData.patientId} options={patients.map(p => ({label: `${p.first_name} ${p.last_name}`, value: p.id}))} onChange={(v: string) => setFormData({...formData, patientId: v})} />
                    <Select label="Doctor" value={formData.doctorId} options={doctors.map(d => ({label: `Dr. ${d.last_name}`, value: d.id}))} onChange={(v: string) => setFormData({...formData, doctorId: v})} />
                    <Input label="Date & Time" type="datetime-local" value={formData.appointment_date} onChange={(v: string) => setFormData({...formData, appointment_date: v})} />
                    <Input label="Status" value={formData.status} onChange={(v: string) => setFormData({...formData, status: v})} />
                  </div>
                )}
              </div>

              <div className="flex gap-4">
                <button onClick={handleSave} className="flex-1 bg-blue-600 text-white py-6 rounded-3xl font-black uppercase text-2xl shadow-lg">Save</button>
                <button onClick={closeModal} className="flex-1 bg-slate-200 text-slate-500 py-6 rounded-3xl font-black uppercase text-xl">Cancel</button>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

// --- SUB-COMPONENTS (With explicit types to fix your error) ---
const Card = ({ title, sub, onEdit, onDelete, color = "border-yellow-400", tag }: CardProps) => (
  <div className={`flex justify-between items-center bg-[#001f3f] p-10 rounded-[40px] border-l-[15px] ${color} shadow-xl hover:bg-blue-900/40 transition-all`}>
    <div>
      <div className="flex items-center gap-4 mb-1">
        <h4 className="text-3xl font-black uppercase italic text-white">{title}</h4>
        {tag && <span className="bg-blue-600 text-[10px] px-3 py-1 rounded-full text-white font-black uppercase tracking-widest">{tag}</span>}
      </div>
      <p className="text-blue-300 font-bold font-mono tracking-tighter">{sub}</p>
    </div>
    <div className="flex gap-6">
      <button onClick={onEdit} className="text-yellow-400 font-black uppercase text-xs border-b-2 border-yellow-400">Edit</button>
      <button onClick={onDelete} className="text-red-500 font-black uppercase text-xs border-b-2 border-red-500">Delete</button>
    </div>
  </div>
);

const Input = ({ label, type = "text", value, onChange }: { label: string, type?: string, value: any, onChange: (val: string) => void }) => (
  <div className="flex flex-col gap-1">
    <label className="text-[10px] font-black uppercase text-slate-400 ml-4">{label}</label>
    <input type={type} className="w-full p-4 bg-slate-100 rounded-2xl border-2 border-transparent focus:border-blue-600 outline-none font-bold text-lg" value={value || ''} onChange={e => onChange(e.target.value)} />
  </div>
);

const Select = ({ label, value, options, onChange }: { label: string, value: any, options: {label: string, value: any}[], onChange: (val: string) => void }) => (
  <div className="flex flex-col gap-1">
    <label className="text-[10px] font-black uppercase text-slate-400 ml-4">{label}</label>
    <select className="w-full p-4 bg-slate-100 rounded-2xl border-2 border-transparent focus:border-blue-600 outline-none font-bold text-lg" value={value || ''} onChange={e => onChange(e.target.value)}>
      <option value="">-- Select --</option>
      {options.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
    </select>
  </div>
);

export default App;
